INSERT INTO modules (id, track_id, stage_index, tier_type, company_tags, content_payload) VALUES ('2c1ea162-1446-497d-b8e1-ee9ed5f2c640', '00000000-0000-0000-0000-000000000002', 0, 'CONCEPT', '{"OpenAI","Anthropic"}', '{"title":"From Chatbots to Agents","content":"# From Chatbots to Agents\n\nAn **agent** is an LLM that decides *what to do next* — it calls tools, observes the results, and loops until the task is done.\n\n## The agent loop\n\n1. The model receives the goal + available tools\n2. It emits a **tool call** (name + arguments)\n3. Your runtime executes the tool and returns the result\n4. The result is appended to the conversation and the model is called again\n5. Repeat until the model returns a final answer\n\n## Why this is hard\n\n- **State**: the model only knows what''s in the message history — you must thread tool results back in\n- **Failure recovery**: tools error, return junk, or time out; the agent must notice and retry or change plan\n- **Termination**: a badly-prompted agent loops forever or stops too early\n\n## ReAct\n\nThe **ReAct** pattern interleaves *Reasoning* (\"I need the user''s order total\") and *Acting* (calling `get_order`). Making the model reason before each action dramatically improves tool selection.","pro_tip":"Always cap the agent loop with a max-iterations guard. An agent with no ceiling will happily burn your entire token budget on one stuck task.","resources":[{"type":"article","label":"ReAct: Reasoning + Acting"},{"type":"read","label":"Tool-calling API reference"}],"difficulty":"Intermediate","learning_objectives":["Explain the agent execution loop","Distinguish an agent from a single LLM call","Apply the ReAct reasoning pattern"],"estimated_duration_minutes":30}'::jsonb) ON CONFLICT (id) DO NOTHING;
INSERT INTO modules (id, track_id, stage_index, tier_type, company_tags, content_payload) VALUES ('d20238b9-4d53-498c-8491-e512a3ed7a94', '00000000-0000-0000-0000-000000000002', 1, 'CODING', '{"OpenAI","Anthropic"}', '{"difficulty":"MEDIUM","description":"Implement the agent loop: given a model that emits tool calls, execute tools and feed results back until a final answer is returned.","starter_files":[{"name":"agent.py","content":"# Implement run_agent(): loop until the model returns {\"type\": \"final\"}.\n# The model function is provided. Each call returns either:\n#   {\"type\": \"tool\", \"name\": str, \"args\": dict}\n#   {\"type\": \"final\", \"answer\": str}\n\nTOOLS = {\n    \"add\": lambda a, b: a + b,\n    \"multiply\": lambda a, b: a * b,\n}\n\n\ndef run_agent(model, goal, max_steps=5):\n    history = [{\"role\": \"user\", \"content\": goal}]\n    for _ in range(max_steps):\n        step = model(history)\n        if step[\"type\"] == \"final\":\n            return step[\"answer\"]\n        # TODO: execute the tool, append the result to history, continue\n        raise NotImplementedError\n    return \"max steps reached\"\n\n\nif __name__ == \"__main__\":\n    # A scripted model for local testing\n    script = [\n        {\"type\": \"tool\", \"name\": \"add\", \"args\": {\"a\": 2, \"b\": 3}},\n        {\"type\": \"final\", \"answer\": \"The sum is 5\"},\n    ]\n    calls = iter(script)\n    print(run_agent(lambda h: next(calls), \"add 2 and 3\"))\n"}],"estimated_duration_minutes":40}'::jsonb) ON CONFLICT (id) DO NOTHING;
INSERT INTO modules (id, track_id, stage_index, tier_type, company_tags, content_payload) VALUES ('9f0428fb-15a9-4268-a9de-47e9337f594d', '00000000-0000-0000-0000-000000000002', 1, 'INTERVIEW', '{"OpenAI","Anthropic"}', '{"title":"Debug the Runaway Agent","difficulty":"MEDIUM","language":"python","description":"## The Bug\n\nThis agent is supposed to stop as soon as the model returns a final answer. Instead it always runs the full `max_steps` and returns \"max steps reached\", even when the model answered on step 1.\n\n## Task\n\nUse the **AI Debugging Assistant** to find why the loop never terminates early. The bug is a single line.\n\n## Constraints\n\n- Do not change the function signature\n- `model` and `TOOLS` are correct","buggy_code":"TOOLS = {\"add\": lambda a, b: a + b}\n\n\ndef run_agent(model, goal, max_steps=5):\n    history = [{\"role\": \"user\", \"content\": goal}]\n    for _ in range(max_steps):\n        step = model(history)\n        if step[\"type\"] == \"final\":\n            answer = step[\"answer\"]  # BUG: captured but the loop keeps going\n        else:\n            result = TOOLS[step[\"name\"]](**step[\"args\"])\n            history.append({\"role\": \"tool\", \"content\": str(result)})\n    return \"max steps reached\"\n"}'::jsonb) ON CONFLICT (id) DO NOTHING;
INSERT INTO modules (id, track_id, stage_index, tier_type, company_tags, content_payload) VALUES ('1cafa71e-6091-4d70-956e-ed6f6ffe73c2', '00000000-0000-0000-0000-000000000003', 0, 'CONCEPT', '{"OpenAI","Anthropic"}', '{"title":"How to Evaluate an LLM System","content":"# How to Evaluate an LLM System\n\nYou can''t improve what you can''t measure. **Evaluation** turns \"the outputs feel better\" into a number you can track across changes.\n\n## Three families of eval\n\n1. **Reference-based**: compare output to a gold answer (exact match, F1, BLEU). Cheap, but brittle for open-ended text.\n2. **LLM-as-judge**: a strong model scores the output against a rubric. Flexible, correlates well with humans, but costs tokens and can be biased.\n3. **Human eval**: the gold standard, the slowest.\n\n## Building an eval set\n\n- Collect real inputs (not made-up ones)\n- Define a **rubric** with explicit criteria\n- Freeze the set so scores are comparable over time\n\n## Watch for judge bias\n\nLLM judges favor longer answers, their own outputs, and the first option shown. Randomize order and calibrate against a few human labels.","pro_tip":"Score on a fixed, frozen eval set. If your test inputs change every run, a score going up tells you nothing about whether the system improved.","resources":[{"type":"article","label":"LLM-as-a-judge, calibrated"},{"type":"read","label":"Building eval sets"}],"difficulty":"Intermediate","learning_objectives":["Compare reference-based vs LLM-as-judge eval","Design a rubric-driven eval set","Identify common LLM-judge biases"],"estimated_duration_minutes":30}'::jsonb) ON CONFLICT (id) DO NOTHING;
INSERT INTO modules (id, track_id, stage_index, tier_type, company_tags, content_payload) VALUES ('d21f444a-d920-474c-9fc8-7d6bfa200068', '00000000-0000-0000-0000-000000000003', 1, 'CODING', '{"OpenAI","Anthropic"}', '{"difficulty":"EASY","description":"Implement a simple exact-match eval: given predictions and gold answers, return accuracy as a float in [0, 1].","starter_files":[{"name":"evaluate.py","content":"# Implement accuracy(): case-insensitive, whitespace-trimmed exact match.\n\ndef accuracy(predictions, golds):\n    \"\"\"Return the fraction of predictions that match their gold answer.\"\"\"\n    if not golds:\n        return 0.0\n    # TODO: normalize (strip + lowercase) and count matches\n    raise NotImplementedError\n\n\nif __name__ == \"__main__\":\n    preds = [\"Paris\", \"  london \", \"Berlin\"]\n    golds = [\"paris\", \"London\", \"Madrid\"]\n    print(accuracy(preds, golds))  # expected 0.6666...\n"}],"estimated_duration_minutes":25}'::jsonb) ON CONFLICT (id) DO NOTHING;
INSERT INTO modules (id, track_id, stage_index, tier_type, company_tags, content_payload) VALUES ('b040aa0d-a35f-46e1-bc78-0ec948482dee', '00000000-0000-0000-0000-000000000003', 1, 'INTERVIEW', '{"OpenAI","Anthropic"}', '{"title":"Debug the Broken Accuracy Metric","difficulty":"EASY","language":"python","description":"## The Bug\n\nThis accuracy function reports **0.0** on inputs that clearly have matches. QA flagged that \"Paris\" vs \"paris\" is being counted as wrong.\n\n## Task\n\nUse the **AI Debugging Assistant** to find why matches are missed. The fix is small.\n\n## Constraints\n\n- Keep the function signature\n- Accuracy must be case- and whitespace-insensitive","buggy_code":"def accuracy(predictions, golds):\n    if not golds:\n        return 0.0\n    matches = 0\n    for p, g in zip(predictions, golds):\n        # BUG: compares raw strings — case and whitespace break the match\n        if p == g:\n            matches += 1\n    return matches / len(golds)\n"}'::jsonb) ON CONFLICT (id) DO NOTHING;
INSERT INTO modules (id, track_id, stage_index, tier_type, company_tags, content_payload) VALUES ('8b6a255a-f74a-4416-8ef7-374b58b19f27', '00000000-0000-0000-0000-000000000004', 0, 'CONCEPT', '{"OpenAI","Anthropic"}', '{"title":"Prompting for Reliable Output","content":"# Prompting for Reliable Output\n\nProduction systems need **structured, parseable** output — not prose. A few techniques get you there.\n\n## Structured output\n\nAsk for JSON and *constrain* it. Most APIs support a `response_format` / JSON mode that guarantees valid JSON. Always specify the exact schema in the prompt.\n\n## Few-shot\n\nShow 2-5 input→output examples. The model pattern-matches the format and edge cases far better than from instructions alone.\n\n## Function calling\n\nInstead of parsing free text, declare tools with typed parameters. The model returns a structured call you can execute directly — no regex.\n\n## Common failure: over-stuffing\n\nA prompt with ten competing instructions performs worse than three clear ones. Put the most important constraint **last** — recency wins.","pro_tip":"When you need JSON, use JSON mode AND give the schema in the prompt. Belt and suspenders — JSON mode guarantees validity, the schema guarantees the right shape.","resources":[{"type":"article","label":"Structured outputs guide"},{"type":"read","label":"Few-shot prompting"}],"difficulty":"Beginner","learning_objectives":["Use JSON mode for parseable output","Apply few-shot examples effectively","Explain when to use function calling"],"estimated_duration_minutes":25}'::jsonb) ON CONFLICT (id) DO NOTHING;
INSERT INTO modules (id, track_id, stage_index, tier_type, company_tags, content_payload) VALUES ('d394103f-3d32-436b-bdb1-2bae0d8e4eba', '00000000-0000-0000-0000-000000000004', 1, 'CODING', '{"OpenAI","Anthropic"}', '{"difficulty":"EASY","description":"Build a few-shot prompt: given examples and a query, produce a single prompt string that lists the examples then the query.","starter_files":[{"name":"prompt.py","content":"# Implement build_few_shot(): format examples as \"Input: ...\\nOutput: ...\",\n# separated by blank lines, then append the query with an empty Output line.\n\ndef build_few_shot(examples, query):\n    \"\"\"examples: list of (input, output) tuples. Returns one prompt string.\"\"\"\n    # TODO: format each example, then the query awaiting completion\n    raise NotImplementedError\n\n\nif __name__ == \"__main__\":\n    ex = [(\"hot\", \"cold\"), (\"up\", \"down\")]\n    print(build_few_shot(ex, \"fast\"))\n"}],"estimated_duration_minutes":25}'::jsonb) ON CONFLICT (id) DO NOTHING;
INSERT INTO modules (id, track_id, stage_index, tier_type, company_tags, content_payload) VALUES ('993b9569-97a9-4dea-85d6-9cb69d4b3db1', '00000000-0000-0000-0000-000000000004', 1, 'INTERVIEW', '{"OpenAI","Anthropic"}', '{"title":"Debug the JSON Parser","difficulty":"MEDIUM","language":"python","description":"## The Bug\n\nThe model returns valid JSON wrapped in a markdown code fence (\\`\\`\\`json ... \\`\\`\\`). This parser crashes with a JSONDecodeError because it tries to parse the fence too.\n\n## Task\n\nUse the **AI Debugging Assistant** to make `parse_model_json` strip the fence before parsing.\n\n## Constraints\n\n- Return the parsed dict\n- Handle both fenced and unfenced JSON","buggy_code":"import json\n\n\ndef parse_model_json(raw: str) -> dict:\n    # Model sometimes wraps JSON in \\`\\`\\`json ... \\`\\`\\` fences.\n    # BUG: parses the raw string directly, fence and all.\n    return json.loads(raw)\n\n\nif __name__ == \"__main__\":\n    out = \"\\`\\`\\`json\\n{\\\"answer\\\": 42}\\n\\`\\`\\`\"\n    print(parse_model_json(out))\n"}'::jsonb) ON CONFLICT (id) DO NOTHING;
INSERT INTO modules (id, track_id, stage_index, tier_type, company_tags, content_payload) VALUES ('da23ad17-9608-4147-a7d0-49e5665c3c8a', '00000000-0000-0000-0000-000000000005', 0, 'CONCEPT', '{"OpenAI","Anthropic"}', '{"title":"Vector Search Fundamentals","content":"# Vector Search Fundamentals\n\nA **vector database** stores embeddings and answers \"which items are most similar to this query?\" — the backbone of every RAG system.\n\n## Embeddings\n\nAn embedding maps text to a fixed-length vector so that similar meanings land close together. Similarity is usually **cosine similarity** (angle between vectors).\n\n## Exact vs approximate\n\n- **Flat (brute force)**: compares the query to every vector. Exact, but O(n) — slow at scale.\n- **ANN (approximate nearest neighbor)**: indexes like **HNSW** trade a tiny bit of recall for massive speedups.\n\n## HNSW in one line\n\nA multi-layer graph where you greedily hop toward the nearest neighbor, starting coarse and refining — logarithmic search instead of linear.\n\n## The knobs that matter\n\nChunk size, embedding dimension, and index type all trade **latency vs recall vs cost**. Bigger isn''t always better.","pro_tip":"Normalize your vectors once at write time, and cosine similarity becomes a plain dot product — faster queries with identical rankings.","resources":[{"type":"article","label":"HNSW explained"},{"type":"read","label":"Cosine vs dot product"}],"difficulty":"Intermediate","learning_objectives":["Explain embeddings and cosine similarity","Contrast Flat vs ANN indexes","Reason about the latency/recall/cost tradeoff"],"estimated_duration_minutes":30}'::jsonb) ON CONFLICT (id) DO NOTHING;
INSERT INTO modules (id, track_id, stage_index, tier_type, company_tags, content_payload) VALUES ('3068118d-e331-4cf6-aee1-09b0016a84ef', '00000000-0000-0000-0000-000000000005', 1, 'CODING', '{"OpenAI","Anthropic"}', '{"difficulty":"MEDIUM","description":"Implement top-k cosine similarity search: given a query vector and a list of vectors, return the indices of the k most similar.","starter_files":[{"name":"search.py","content":"import math\n\n# Implement top_k(): return indices of the k vectors most similar to query\n# by cosine similarity, highest first.\n\ndef cosine(a, b):\n    dot = sum(x * y for x, y in zip(a, b))\n    na = math.sqrt(sum(x * x for x in a))\n    nb = math.sqrt(sum(y * y for y in b))\n    return dot / (na * nb) if na and nb else 0.0\n\n\ndef top_k(query, vectors, k=2):\n    # TODO: score every vector, return the indices of the top k\n    raise NotImplementedError\n\n\nif __name__ == \"__main__\":\n    q = [1, 0]\n    vs = [[1, 0], [0, 1], [0.9, 0.1]]\n    print(top_k(q, vs, 2))  # expected [0, 2]\n"}],"estimated_duration_minutes":35}'::jsonb) ON CONFLICT (id) DO NOTHING;
INSERT INTO modules (id, track_id, stage_index, tier_type, company_tags, content_payload) VALUES ('77b5abbd-89e8-4b34-85d3-9f3cb90bdda0', '00000000-0000-0000-0000-000000000005', 1, 'INTERVIEW', '{"OpenAI","Anthropic"}', '{"title":"Debug the Similarity Ranking","difficulty":"MEDIUM","language":"python","description":"## The Bug\n\nThis top-k search returns the **least** similar vectors instead of the most similar. Users complain retrieval brings back irrelevant chunks.\n\n## Task\n\nUse the **AI Debugging Assistant** to find why the ranking is inverted. One line is wrong.\n\n## Constraints\n\n- Return indices, highest similarity first\n- `cosine` is correct","buggy_code":"import math\n\n\ndef cosine(a, b):\n    dot = sum(x * y for x, y in zip(a, b))\n    na = math.sqrt(sum(x * x for x in a))\n    nb = math.sqrt(sum(y * y for y in b))\n    return dot / (na * nb) if na and nb else 0.0\n\n\ndef top_k(query, vectors, k=2):\n    scored = [(cosine(query, v), i) for i, v in enumerate(vectors)]\n    # BUG: sorts ascending, so least-similar come first\n    scored.sort()\n    return [i for _, i in scored[:k]]\n"}'::jsonb) ON CONFLICT (id) DO NOTHING;
